const b   = $('Webhook - POST /vmm-send-escalation-email').first().json.body || {};
const cfg = $('Email Config').first().json;

// ── Inputs from CRM app ──────────────────────────────────────────────
const escalationType = (b.escalationType || 'vendor').toLowerCase(); // 'vendor' | 'fm'
const vendorEmail    = (b.vendorEmail    || '').trim();
const vendorName     = (b.vendorName     || '').trim();
const smEmail        = (b.smEmail        || b.storeEmail || '').trim();
const fmEmail        = (b.fmEmail        || '').trim();
const hoEmail        = (b.hoEmail        || '').trim();
const storeName      = (b.storeName      || 'Store').trim();
const storeCode      = (b.storeCode      || '').trim();
const productName    = (b.productName    || 'Product').trim();
const contractType   = (b.contractType   || '').trim(); // 'AMC' | 'Warranty' | 'NotApplicable'
const complaints     = Array.isArray(b.complaints) ? b.complaints : [];

if (!complaints.length) return [{ json: { skipped: true, message: 'No complaints provided' } }];

const totalUnits   = complaints.length;
const complaintnos = complaints.map(c => c.complaintno).filter(Boolean);

// ── Resolve TO and CC based on escalation type ───────────────────────
// vendor route: TO = vendor, CC = SM + HO + FM
// fm route:     TO = FM,     CC = SM + HO

let primaryTo = '';
const ccList  = [];

if (escalationType === 'vendor') {
  primaryTo = vendorEmail;
  if (smEmail) ccList.push(smEmail);
  if (hoEmail && hoEmail !== smEmail) ccList.push(hoEmail);
  if (fmEmail && !ccList.includes(fmEmail)) ccList.push(fmEmail);
} else {
  // fm / ho team route
  primaryTo = fmEmail;
  if (smEmail) ccList.push(smEmail);
  if (hoEmail && hoEmail !== smEmail) ccList.push(hoEmail);
}

// Always add the Teams channel
if (cfg.ALWAYS_CC) {
  cfg.ALWAYS_CC.split(',').map(e => e.trim()).filter(Boolean).forEach(e => {
    if (!ccList.includes(e) && e !== primaryTo) ccList.push(e);
  });
}

const toAddress = cfg.TEST_MODE ? cfg.TEST_TO : primaryTo;
const ccAddress = cfg.TEST_MODE ? '' : ccList.join(';');

// ── Subject ──────────────────────────────────────────────────────────
const storeLabel = storeName + (storeCode ? ' (' + storeCode + ')' : '');
const typeLabel  = contractType === 'Warranty' ? 'Warranty' : 'AMC';

const subject = totalUnits > 1
  ? 'VMM Escalation — ' + productName + ' [' + typeLabel + '] — ' + storeLabel
  : 'VMM Complaint Escalation — ' + (complaints[0].complaintno || '') + ' — ' + storeLabel;

// ── Table rows ───────────────────────────────────────────────────────
const rows = complaints.map((c, i) =>
  '<tr>'
  + '<td style="padding:9px 12px;background:#f8fafc;font-weight:700;text-align:center;border-bottom:1px solid #e2e8f0">' + (i + 1) + '</td>'
  + '<td style="padding:9px 12px;border-bottom:1px solid #e2e8f0;font-weight:800;color:#1e1b4b">' + (c.complaintno || '—') + '</td>'
  + '<td style="padding:9px 12px;border-bottom:1px solid #e2e8f0">' + (c.productLocation || '—') + '</td>'
  + '<td style="padding:9px 12px;border-bottom:1px solid #e2e8f0;color:' + (contractType === 'Warranty' ? '#ea580c' : '#475569') + '">' + (contractType || 'AMC') + '</td>'
  + '<td style="padding:9px 12px;border-bottom:1px solid #e2e8f0">' + (c.natureOfProblem || '—') + '</td>'
  + '<td style="padding:9px 12px;border-bottom:1px solid #e2e8f0;font-weight:700;color:#dc2626">' + (c.edcDate || '—') + '</td>'
  + '</tr>'
).join('');

// ── Greeting line based on escalation type ───────────────────────────
const greeting = escalationType === 'vendor'
  ? 'Dear <strong>' + (vendorName || 'Vendor Team') + '</strong>,'
  : 'Dear Facility Manager,';

const bodyIntro = escalationType === 'vendor'
  ? (totalUnits > 1
      ? '<strong>' + totalUnits + ' facility complaint(s)</strong> have been logged for <strong>' + productName + '</strong> at store <strong>' + storeLabel + '</strong>. Please attend to each unit and ensure resolution within the specified timelines.'
      : 'A facility complaint has been logged for <strong>' + productName + '</strong> at <strong>' + storeLabel + '</strong>. Kindly attend to this and resolve within the committed timeline.')
  : (totalUnits > 1
      ? '<strong>' + totalUnits + ' facility complaint(s)</strong> regarding <strong>' + productName + '</strong> at store <strong>' + storeLabel + '</strong> require your attention. Please coordinate with the relevant vendor/team for resolution.'
      : 'A facility complaint regarding <strong>' + productName + '</strong> at <strong>' + storeLabel + '</strong> requires your attention.');

const htmlBody =
  '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.7;max-width:700px">'
  + '<p>' + greeting + '</p>'
  + '<p>' + bodyIntro + '</p>'
  + '<table style="border-collapse:collapse;width:100%;margin:14px 0">'
  + '<thead><tr>'
  + '<th style="padding:9px 12px;background:#1e1b4b;color:#fff;text-align:center;width:36px">#</th>'
  + '<th style="padding:9px 12px;background:#1e1b4b;color:#fff;text-align:left">Complaint No</th>'
  + '<th style="padding:9px 12px;background:#1e1b4b;color:#fff;text-align:left">Unit Location</th>'
  + '<th style="padding:9px 12px;background:#1e1b4b;color:#fff;text-align:left">Contract</th>'
  + '<th style="padding:9px 12px;background:#1e1b4b;color:#fff;text-align:left">Nature of Problem</th>'
  + '<th style="padding:9px 12px;background:#1e1b4b;color:#fff;text-align:left">Expected Closure</th>'
  + '</tr></thead>'
  + '<tbody>' + rows + '</tbody>'
  + '</table>'
  + '<p>Please ensure timely resolution. Do not reply to this email — log updates through the CRM.</p>'
  + '<hr style="margin:16px 0;border:none;border-top:1px solid #e2e8f0"/>'
  + '<p style="font-size:11px;color:#64748b">Automated escalation from VMM CRM — Open Mind Services Limited.</p>'
  + (cfg.TEST_MODE
      ? '<hr style="margin:12px 0;border:none;border-top:1px solid #fcd34d"/>'
        + '<p style="font-size:11px;color:#92400e"><strong>TEST MODE</strong> — '
        + 'Type: ' + escalationType + ' | '
        + 'Actual TO: ' + primaryTo + ' | '
        + 'Actual CC: ' + ccList.join('; ') + '</p>'
      : '')
  + '</div>';

return [{ json: { subject, htmlBody, toAddress, ccAddress, complaintnos, cloudUrl: cfg.CLOUD_URL } }];

const cloudRes     = $input.first().json || {};
const buildData    = $('Build Email Content').first().json;
const messageId    = cloudRes.messageId    || '';
const complaintnos = buildData.complaintnos || [];

let updateSql = 'SELECT 1';
if (messageId && complaintnos.length > 0) {
  const safeId  = messageId.replace(/'/g, "''");
  const nosStr  = complaintnos.map(n => `'${n.replace(/'/g, "''")}'`).join(',');
  updateSql = `UPDATE vmm_complaints SET escalation_messageid = '${safeId}' WHERE complaintno IN (${nosStr})`;
}

return [{ json: { messageId, updateSql, success: !!messageId } }];
